import Foundation

final class NetworkViewModel: ObservableObject {
    @Published var output: String = "Tap a button to start."
    @Published var isLoading: Bool = false

    func fetchSecure() {
        guard let url = URL(string: "https://api.example.com") else {
            output = "Invalid secure URL"
            return
        }
        performRequest(url: url)
    }

    func fetchLegacy() {
        guard let url = URL(string: "http://legacy.internal") else {
            output = "Invalid legacy URL"
            return
        }
        performRequest(url: url)
    }

    private func performRequest(url: URL) {
        isLoading = true
        output = "Loading \(url.absoluteString)..."

        let task = URLSession.shared.dataTask(with: url) { [weak self] data, response, error in
            DispatchQueue.main.async {
                self?.isLoading = false

                if let error = error {
                    self?.output = "Error: \(error.localizedDescription)"
                    return
                }

                if let httpResponse = response as? HTTPURLResponse {
                    var result = "Status: \(httpResponse.statusCode)\n"
                    result += "URL: \(url.absoluteString)\n\n"
                    if let data = data, let body = String(data: data, encoding: .utf8), !body.isEmpty {
                        result += body
                    } else {
                        result += "No response body"
                    }
                    self?.output = result
                } else {
                    self?.output = "No valid HTTP response"
                }
            }
        }

        task.resume()
    }
}